/**
 * Record when each album was completed, from the studio drive.
 *
 *   J:\music\angels\{NN}_{Book}\{CODE} {Album}\tracks\*.mp3
 *
 * "Completed" = the newest track mtime in the album's tracks/ folder, i.e. when
 * the last song landed on the drive. That is the only completion signal that
 * exists — nothing in the catalogue records a release date — and it is stable:
 * once a file is written its mtime does not move, so a past week's numbers stay
 * put without needing to be frozen.
 *
 * Kept OUT of angels-catalog.ts on purpose. That file is regenerated by the
 * catalogue scan and reviewed as content; these are timestamps about the drive,
 * they change for different reasons, and Production History is the only reader.
 *
 * Run: node scripts/gen-completion-dates.mjs
 */

import { readdirSync, statSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';

const ROOT = process.env.ANGELS_ROOT || 'J:/music/angels';
const OUT = new URL('../src/content/completion-dates.ts', import.meta.url);

const dirs = (p) => {
  try {
    return readdirSync(p).filter((name) => {
      try {
        return statSync(join(p, name)).isDirectory();
      } catch {
        return false;
      }
    });
  } catch {
    return [];
  }
};

const dates = {};
let scanned = 0;

for (const book of dirs(ROOT).sort()) {
  for (const albumDir of dirs(join(ROOT, book)).sort()) {
    const sp = albumDir.indexOf(' ');
    const code = sp === -1 ? albumDir : albumDir.slice(0, sp);
    const tracksDir = join(ROOT, book, albumDir, 'tracks');

    let newest = 0;
    let files = [];
    try {
      files = readdirSync(tracksDir).filter((f) => f.toLowerCase().endsWith('.mp3'));
    } catch {
      continue;
    }
    for (const f of files) {
      try {
        const s = statSync(join(tracksDir, f));
        if (s.mtimeMs > newest) newest = s.mtimeMs;
      } catch {
        /* unreadable file — the others still count */
      }
    }
    // No tracks means nothing has been completed, not "completed at epoch".
    if (!newest) continue;
    dates[code] = new Date(newest).toISOString();
    scanned += 1;
  }
}

const sorted = Object.keys(dates).sort().reduce((acc, k) => ((acc[k] = dates[k]), acc), {});
const stamps = Object.values(sorted).sort();

const header = `// AUTO-GENERATED by scripts/gen-completion-dates.mjs — do not edit by hand.
// Source: ${ROOT}
// ${scanned} albums · ${stamps[0]?.slice(0, 10) ?? '—'} → ${stamps[stamps.length - 1]?.slice(0, 10) ?? '—'}
//
// Album code -> ISO timestamp of the newest track on the drive: when the album
// was finished. Read only by lib/productionHistory.ts.

export const completionDates: Record<string, string> = `;

writeFileSync(OUT, header + JSON.stringify(sorted, null, 2) + ';\n', 'utf8');

console.log(
  `Wrote ${OUT.pathname.replace(/^\//, '')}\n` +
    `  ${scanned} albums · ${stamps[0]?.slice(0, 10)} → ${stamps[stamps.length - 1]?.slice(0, 10)}`,
);
